const cities = ["Dallas", "Fort Worth", "Arlington", "Plano", "Garland", "Irving", "McKinney", "Frisco", "Mesquite", "Grand Prairie", "Carrollton", "Richardson", "Lewisville", "Allen", "Flower Mound"];
const collections = ["Classic™ Steel", "Bridgeport™ Steel", "Coachman®", "Modern Steel™", "Canyon Ridge® Collection"];
const sizes = ["8x7", "9x7", "10x7", "16x7", "16x8", "18x7", "18x8"];
const designs = ["Short Panel", "Long Panel"];
const colors = ["White", "Almond", "Desert Tan", "Sandtone", "Bronze", "Chocolate", "Charcoal", "Gray", "Black"];
const constructions = ["2\" Intellicore® Insulated R-18", "1 3/8\" Intellicore R-12", "2\" Polystyrene R-9", "1 3/8\" Polystyrene R-6"];

function pick(arr) { return arr[Math.floor(Math.random() * arr.length)]; }
let config = null; let attempts = 0;
while (!config && attempts < 50) {
  attempts++;
  const c = { PhoneNumber: pick(numbers), Location: pick(cities) + ', Texas', Collection: pick(collections), Size: pick(sizes), Design: pick(designs), Color: pick(colors), Construction: pick(constructions), Video_URL: '/opt/fb-marketplace-bot/ffb88fcc-ff51-4ce6-87f2-016eabca6a4d.mp4' };
  if (!existingConfigs.has(`${c.Collection}|${c.Size}|${c.Design}|${c.Color}`)) { config = c; }
}
const c = config || { PhoneNumber: pick(numbers), Location: 'Dallas, Texas', Collection: 'Classic™ Steel', Size: '8x7', Design: 'Short Panel', Color: 'White', Construction: 'R-6', Video_URL: '/opt/fb-marketplace-bot/ffb88fcc-ff51-4ce6-87f2-016eabca6a4d.mp4' };
const sizePrices = { '8x7': 1800, '9x7': 2000, '10x7': 2200, '16x7': 3400, '16x8': 3800, '18x7': 4200, '18x8': 4600 };
const total = Math.round((sizePrices[c.Size] || 2500) * 1.1 * (0.95 + Math.random() * 0.1));
const hash = `${c.Collection}|${c.Size}|${c.Design}|${c.Color}|${Date.now()}`;
const phone = 'CALL ' + c.PhoneNumber;
return [{ json: { ...c, Price: total, ListingPrice: total, uniqueHash: hash,
  prompt1: `${c.Color} ${c.Collection} garage door on Texas home, ${c.Design}, professional daylight, text overlay: ${phone}`,
  prompt2: `Close up of ${c.Color} ${c.Collection} garage door, ${c.Design}, high resolution suburban photo`,
  prompt3: `Wide shot: ${c.Color} ${c.Collection} garage door, ${c.Design} design, Texas curb appeal`
}}];

